import { Button, Container, makeStyles, Paper } from '@material-ui/core'
import { React, useRef, useState } from 'react'
import Webcam from 'react-webcam'

const videoConstraints = {
    width: 1280,
    height: 720,
    facingMode: "user"
};

const useStyle = makeStyles(theme => {
    return {
        paper: {
            padding: '20px',
            display: 'flex',
            justifyContent: 'center'
        }
    }
})

export default function VideoStream() {
    const classes = useStyle()
    const webref = useRef(true)
    const [showImage, setShowImage] = useState(null)
    const handleSnap = () => {
       let img = webref.current.getScreenShot()
       setShowImage(img)
    }
    return (
        <div>
            <Paper className={classes.paper}>
                <Container>
                <Webcam
                
                    audio={false}
                    height='auto'
                    screenshotFormat="image/jpeg"
                    width={450}
                    videoConstraints={videoConstraints} />
                <Button onClick={handleSnap} variant='contained'color='secondary' fullWidth >Snap</Button>
                
                <img src={showImage} alt="" />
                </Container>
            </Paper>
        </div>
    )
}
